import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import SkeletonLoader from '../common/SkeletonLoader';
import { Bell, AlertCircle, Info, CheckCircle, Filter } from 'lucide-react';

const Announcements = () => {
  const [announcements, setAnnouncements] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('All');
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    fetchAnnouncements();
  }, []);

  const fetchAnnouncements = async () => {
    try {
      const { data } = await api.get('/announcements');
      setAnnouncements(data || []);
      
      // Count unread
      const unread = data?.filter(a => !a.readBy?.some(r => r.userId === localStorage.getItem('userId'))).length || 0;
      setUnreadCount(unread);
      setLoading(false);
    } catch (error) {
      console.error('Failed to fetch announcements:', error);
      setAnnouncements([]);
      setLoading(false);
    }
  };

  const markAsRead = async (id) => {
    try {
      await api.put(`/announcements/${id}/read`);
      fetchAnnouncements();
    } catch (error) {
      console.error('Failed to mark as read:', error);
    }
  };

  const getPriorityIcon = (priority) => {
    switch (priority) {
      case 'Urgent':
        return <AlertCircle className="text-red-500" size={20} />;
      case 'Success':
        return <CheckCircle className="text-green-500" size={20} />;
      default:
        return <Info className="text-blue-500" size={20} />;
    }
  };

  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'Urgent':
        return 'bg-red-50 border-red-200 text-red-800';
      case 'Success':
        return 'bg-green-50 border-green-200 text-green-800';
      default:
        return 'bg-blue-50 border-blue-200 text-blue-800';
    }
  };

  const filteredAnnouncements = announcements.filter(a => {
    if (filter === 'Unread') {
      return !a.readBy?.some(r => r.userId);
    }
    if (filter === 'Urgent') {
      return a.priority === 'Urgent';
    }
    return true;
  });

  if (loading) {
    return <SkeletonLoader count={3} type="card" />;
  }

  return (
    <div className="mb-6">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
          <Bell size={24} className="text-blue-600" />
          Announcements
          {unreadCount > 0 && (
            <span className="bg-red-500 text-white text-xs px-2 py-0.5 rounded-full font-bold">
              {unreadCount}
            </span>
          )}
        </h2>
      </div>

      {/* Filter Buttons */}
      <div className="flex gap-2 mb-4 overflow-x-auto pb-2">
        {['All', 'Unread', 'Urgent'].map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            className={`px-4 py-1.5 rounded-full text-sm font-bold whitespace-nowrap transition ${
              filter === f
                ? 'bg-blue-600 text-white'
                : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
            }`}
          >
            {f}
          </button>
        ))}
      </div>

      {/* Announcements List */}
      {filteredAnnouncements.length > 0 ? (
        <div className="space-y-3">
          {filteredAnnouncements.map((announcement) => {
            const isRead = announcement.readBy?.some(r => r.userId);
            return (
              <div
                key={announcement._id}
                onClick={() => markAsRead(announcement._id)}
                className={`p-4 rounded-xl border-2 cursor-pointer transition ${getPriorityColor(announcement.priority)} ${
                  !isRead ? 'ring-2 ring-yellow-400' : 'opacity-75'
                }`}
              >
                <div className="flex gap-3">
                  <div className="flex-shrink-0">
                    {getPriorityIcon(announcement.priority)}
                  </div>
                  <div className="flex-1">
                    <h3 className="font-bold text-sm mb-1">{announcement.title}</h3>
                    <p className="text-xs line-clamp-2">{announcement.content}</p>
                    <div className="flex justify-between items-center mt-2">
                      <span className="text-[10px] opacity-70">
                        By {announcement.createdBy?.name}
                      </span>
                      {!isRead && (
                        <span className="text-[10px] font-bold bg-white/50 px-2 py-0.5 rounded">
                          New
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="text-center py-8 text-gray-400">
          <Bell size={40} className="mx-auto mb-2 opacity-50" />
          <p>No announcements yet</p>
        </div>
      )}
    </div>
  );
};

export default Announcements;

import React, { useState } from 'react';
import api from '../../services/api';
import { Save, X, Droplet } from 'lucide-react';

const EditBloodGroup = ({ currentGroup, onUpdate, onClose }) => {
  const [selected, setSelected] = useState(currentGroup || 'O+');
  const [loading, setLoading] = useState(false);

  const bloodTypes = ['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'];

  const handleSave = async () => {
    setLoading(true);
    try {
      // Direct API call to update profile
      const { data } = await api.put('/users/profile', { bloodGroup: selected });
      
      // Update parent state and close modal
      if (onUpdate) onUpdate(selected);
      if (onClose) onClose();
      
    } catch (error) {
      console.error("Update failed", error);
      alert("Failed to update blood group. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      {/* Modal Container */}
      <div className="bg-white rounded-2xl p-6 w-full max-w-xs shadow-2xl animate-in zoom-in-95 border border-gray-100">
        
        {/* Header */}
        <div className="flex justify-between items-center mb-6">
          <h3 className="font-bold text-gray-900 flex items-center gap-2 text-lg">
            <Droplet className="text-red-600 fill-red-600" size={24} /> 
            Select Blood Group
          </h3>
          <button 
            onClick={onClose} 
            className="p-2 hover:bg-gray-100 rounded-full text-gray-500 hover:text-gray-800 transition-colors"
          >
            <X size={24} />
          </button>
        </div>

        {/* Selection Grid */}
        <div className="grid grid-cols-4 gap-3 mb-6">
          {bloodTypes.map((type) => (
            <button
              key={type}
              onClick={() => setSelected(type)}
              className={`
                py-3 px-1 rounded-xl text-sm font-bold border transition-all duration-200
                ${selected === type 
                  ? 'bg-red-600 text-white border-red-600 shadow-md transform scale-105' 
                  : 'bg-white text-gray-700 border-gray-200 hover:border-red-300 hover:bg-red-50'
                }
              `}
            >
              {type}
            </button>
          ))}
        </div>

        {/* Action Button */}
        <button
          onClick={handleSave}
          disabled={loading}
          className="w-full py-3.5 bg-gray-900 text-white rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-black active:scale-95 transition-all shadow-lg disabled:opacity-70 disabled:cursor-not-allowed"
        >
          {loading ? (
            <span className="animate-pulse">Saving...</span>
          ) : (
            <>
              <Save size={20} /> Update Profile
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export default EditBloodGroup;

import React, { useState, useEffect } from 'react';
import { MessageCircle, BarChart3, X } from 'lucide-react';
import api from '../../services/api';

const PollComponent = ({ poll, onVote, onClose }) => {
  const [selectedOption, setSelectedOption] = useState(null);
  const [hasVoted, setHasVoted] = useState(false);
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);

  useEffect(() => {
    fetchResults();
  }, [poll._id]);

  const fetchResults = async () => {
    try {
      const response = await api.get(`/polls/${poll._id}/results`);
      setResults(response.data.data);
    } catch (error) {
      console.error('Failed to fetch poll results:', error);
    }
  };

  const handleVote = async () => {
    if (selectedOption === null) return;

    setLoading(true);
    try {
      await api.put(`/polls/${poll._id}/vote`, { optionIndex: selectedOption });
      setHasVoted(true);
      await fetchResults();
      if (onVote) onVote();
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to vote');
    } finally {
      setLoading(false);
    }
  };

  const timeLeft = new Date(poll.expiresAt) - new Date();
  const hoursLeft = Math.floor(timeLeft / (1000 * 60 * 60));
  const minutesLeft = Math.floor((timeLeft % (1000 * 60 * 60)) / (1000 * 60));

  return (
    <div className="bg-white rounded-lg shadow-md p-6 mb-4 border-l-4 border-blue-500">
      <div className="flex justify-between items-start mb-4">
        <div className="flex-1">
          <h3 className="text-lg font-bold text-gray-800">{poll.title}</h3>
          {poll.description && <p className="text-sm text-gray-600 mt-1">{poll.description}</p>}
          <div className="flex items-center gap-4 mt-2 text-xs text-gray-500">
            <span className="flex items-center gap-1">
              <BarChart3 size={14} /> {results?.totalVotes || 0} votes
            </span>
            <span>
              {hoursLeft}h {minutesLeft}m left
            </span>
          </div>
        </div>
        {onClose && (
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <X size={20} />
          </button>
        )}
      </div>

      <div className="space-y-3">
        {poll.options.map((option, index) => {
          const percentage =
            results?.totalVotes > 0 ? ((results?.results[index]?.votes / results?.totalVotes) * 100).toFixed(0) : 0;

          return (
            <div key={index} className={`p-3 border rounded-lg transition cursor-pointer ${
              selectedOption === index ? 'border-blue-500 bg-blue-50' : 'border-gray-200 hover:border-gray-300'
            }`}>
              <label className="flex items-center gap-3">
                <input
                  type="radio"
                  name="poll-option"
                  value={index}
                  checked={selectedOption === index}
                  onChange={() => setSelectedOption(index)}
                  disabled={hasVoted || loading}
                  className="w-4 h-4"
                />
                <span className="flex-1 text-sm font-medium text-gray-700">{option.text}</span>
              </label>

              {results && results.totalVotes > 0 && (
                <div className="mt-2 ml-7">
                  <div className="w-full bg-gray-200 rounded-full h-2">
                    <div className="bg-blue-500 h-2 rounded-full" style={{ width: `${percentage}%` }} />
                  </div>
                  <p className="text-xs text-gray-500 mt-1">
                    {results?.results[index]?.votes} votes ({percentage}%)
                  </p>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {!hasVoted && (
        <button
          onClick={handleVote}
          disabled={selectedOption === null || loading || !poll.isActive}
          className="w-full mt-4 bg-blue-600 text-white py-2 rounded-lg font-medium hover:bg-blue-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition"
        >
          {loading ? 'Submitting...' : 'Vote'}
        </button>
      )}

      {hasVoted && <p className="text-sm text-green-600 font-medium mt-4">✓ Your vote has been recorded</p>}
    </div>
  );
};

export default PollComponent;

