import React, { useState, useContext } from 'react';
import { AuthContext } from '../../context/AuthContext';
import api from '../../services/api';
import { X, Send, AlertCircle, Info, CheckCircle, Clock } from 'lucide-react';

const CreateAnnouncementForm = ({ onClose, onSuccess }) => {
  const { user } = useContext(AuthContext);
  const [formData, setFormData] = useState({
    title: '',
    content: '',
    priority: 'Info',
    scope: 'Global',
    domain: '',
    expiresAt: ''
  });
  const [domains, setDomains] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const isSecondary = user?.role?.toLowerCase() === 'secretary';
  const isDomainHead = user?.role?.toLowerCase() === 'domain head';

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (!formData.title.trim() || !formData.content.trim()) {
      setError('Title and content are required');
      return;
    }

    if (formData.scope === 'Domain' && !formData.domain) {
      setError('Please select a domain for domain-scoped announcement');
      return;
    }

    setLoading(true);

    try {
      const payload = {
        title: formData.title.trim(),
        content: formData.content.trim(),
        priority: formData.priority,
        scope: formData.scope,
        ...(formData.scope === 'Domain' && { domainId: formData.domain }),
        ...(formData.expiresAt && { expiresAt: formData.expiresAt })
      };

      await api.post('/announcements', payload);
      setFormData({
        title: '',
        content: '',
        priority: 'Info',
        scope: 'Global',
        domain: '',
        expiresAt: ''
      });
      onSuccess?.();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create announcement');
    } finally {
      setLoading(false);
    }
  };

  // Fetch available domains for Domain Heads / Secretary
  React.useEffect(() => {
    let mounted = true;
    const fetchDomains = async () => {
      try {
        const { data } = await api.get('/domains');
        if (mounted) setDomains(Array.isArray(data) ? data : []);
      } catch (err) {
        // silently ignore – domain list is optional
      }
    };
    fetchDomains();
    return () => { mounted = false; };
  }, []);

  const getPriorityIcon = (priority) => {
    switch(priority) {
      case 'Urgent': return <AlertCircle size={16} className="text-red-500" />;
      case 'Success': return <CheckCircle size={16} className="text-green-500" />;
      default: return <Info size={16} className="text-blue-500" />;
    }
  };

  const getPriorityColor = (priority) => {
    switch(priority) {
      case 'Urgent': return 'ring-2 ring-red-200 bg-red-50';
      case 'Success': return 'ring-2 ring-green-200 bg-green-50';
      default: return 'ring-2 ring-blue-200 bg-blue-50';
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md max-h-[90vh] overflow-y-auto">
        {/* Header */}
        <div className="sticky top-0 bg-gradient-to-b from-blue-600 to-blue-500 text-white p-6 flex items-center justify-between">
          <h2 className="text-xl font-black tracking-tight">New Announcement</h2>
          <button
            onClick={onClose}
            className="bg-white/20 p-2 rounded-full hover:bg-white/30 transition-colors"
          >
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          {/* Error Message */}
          {error && (
            <div className="bg-red-50 border border-red-200 rounded-xl p-3 flex gap-2 text-sm text-red-700">
              <AlertCircle size={16} className="flex-shrink-0 mt-0.5" />
              <p>{error}</p>
            </div>
          )}

          {/* Title */}
          <div>
            <label htmlFor="announcement-title" className="block text-xs font-bold text-gray-600 uppercase tracking-widest mb-2">
              Title *
            </label>
            <input
              id="announcement-title"
              type="text"
              name="title"
              value={formData.title}
              onChange={handleChange}
              placeholder="e.g., Important Meeting Tomorrow"
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 outline-none transition-all bg-gray-50 placeholder-gray-400 text-gray-900"
              maxLength={100}
            />
            <p className="text-[10px] text-gray-400 mt-1">{formData.title.length}/100</p>
          </div>

          {/* Content */}
          <div>
            <label htmlFor="announcement-content" className="block text-xs font-bold text-gray-600 uppercase tracking-widest mb-2">
              Message *
            </label>
            <textarea
              id="announcement-content"
              name="content"
              value={formData.content}
              onChange={handleChange}
              placeholder="Write your announcement here..."
              rows={4}
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 outline-none transition-all resize-none bg-gray-50 placeholder-gray-400 text-gray-900"
              maxLength={500}
            />
            <p className="text-[10px] text-gray-400 mt-1">{formData.content.length}/500</p>
          </div>

          {/* Priority */}
          <div>
            <label className="block text-xs font-bold text-gray-600 uppercase tracking-widest mb-2">
              Priority Level
            </label>
            <div className="grid grid-cols-3 gap-2">
              {['Urgent', 'Info', 'Success'].map(priority => (
                <button
                  key={priority}
                  type="button"
                  onClick={() => setFormData(prev => ({ ...prev, priority }))}
                  className={`py-3 px-2 rounded-xl font-bold text-xs uppercase tracking-wider transition-all flex items-center justify-center gap-1 ${
                    formData.priority === priority
                      ? getPriorityColor(priority)
                      : 'bg-gray-50 text-gray-600 border border-gray-200'
                  }`}
                >
                  {getPriorityIcon(priority)}
                  {priority}
                </button>
              ))}
            </div>
          </div>

          {/* Scope */}
          <div>
            <label className="block text-xs font-bold text-gray-600 uppercase tracking-widest mb-2">
              Visibility
            </label>
            <div className="space-y-2">
              {isSecondary && (
                <label className="flex items-center gap-3 p-3 rounded-xl border border-gray-200 hover:bg-gray-50 cursor-pointer transition-colors">
                  <input
                    type="radio"
                    name="scope"
                    value="Global"
                    checked={formData.scope === 'Global'}
                    onChange={handleChange}
                    className="w-5 h-5 accent-blue-600"
                  />
                  <div>
                    <p className="font-bold text-sm text-gray-800">All Volunteers</p>
                    <p className="text-[10px] text-gray-400">Reach everyone in the organization</p>
                  </div>
                </label>
              )}

              {isDomainHead && (
                <label className="flex items-center gap-3 p-3 rounded-xl border border-gray-200 hover:bg-gray-50 cursor-pointer transition-colors">
                  <input
                    type="radio"
                    name="scope"
                    value="Domain"
                    checked={formData.scope === 'Domain'}
                    onChange={handleChange}
                    className="w-5 h-5 accent-blue-600"
                  />
                  <div>
                    <p className="font-bold text-sm text-gray-800">My Domain</p>
                    <p className="text-[10px] text-gray-400">Only show to your domain members</p>
                  </div>
                </label>
              )}
            </div>
          </div>

          {/* Domain Select (if Domain Head) */}
          {isDomainHead && formData.scope === 'Domain' && (
            <div>
              <label htmlFor="announcement-domain" className="block text-xs font-bold text-gray-600 uppercase tracking-widest mb-2">
                Select Domain *
              </label>
              <select
                id="announcement-domain"
                name="domain"
                value={formData.domain}
                onChange={handleChange}
                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 outline-none transition-all bg-gray-50"
              >
                <option value="">-- Choose a domain --</option>
                {domains.map(d => (
                  <option key={d._id} value={d._id}>{d.name}</option>
                ))}
              </select>
            </div>
          )}

          {/* Expiration */}
          <div>
            <label className="block text-xs font-bold text-gray-600 uppercase tracking-widest mb-2 flex items-center gap-1">
              <Clock size={14} /> Expires (Optional)
            </label>
            <input
              type="datetime-local"
              name="expiresAt"
              value={formData.expiresAt}
              onChange={handleChange}
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 outline-none transition-all bg-gray-50"
            />
            <p className="text-[10px] text-gray-400 mt-1">Announcement will be hidden after this time</p>
          </div>

          {/* Submit */}
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-gradient-to-r from-blue-600 to-blue-500 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 active:scale-95 transition-all disabled:opacity-50 disabled:cursor-not-allowed uppercase tracking-wider text-sm"
          >
            {loading ? (
              <>
                <div className="w-4 h-4 border-2 border-white border-t-transparent animate-spin rounded-full" />
                Publishing...
              </>
            ) : (
              <>
                <Send size={18} />
                Publish Announcement
              </>
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default CreateAnnouncementForm;

import React, { useState } from 'react';
import QRCode from 'react-qr-code';
import api from '../../services/api';
import Input from '../common/Input';
import Button from '../common/Button';
import { MapPin, Calendar, QrCode, AlertCircle } from 'lucide-react';

const CreateEventForm = () => {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    date: '',
    type: 'Volunteer',
    latitude: '',
    longitude: '',
    radius: 100 // Default 100 meters
  });
  const [createdEventId, setCreatedEventId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Helper: Get Current GPS for the Event Location
  const getCurrentLocation = () => {
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser");
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setFormData(prev => ({
          ...prev,
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude
        }));
      },
      (err) => {
        alert("Unable to retrieve location. Please allow GPS access.");
      }
    );
  };

  const handleChange = (e) => setFormData({...formData, [e.target.name]: e.target.value});

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    
    try {
      // API call to create event
      const { data } = await api.post('/events', formData); 
      setCreatedEventId(data._id); // Save ID to generate QR
    } catch (err) {
      setError(err.response?.data?.message || "Failed to create event. Ensure backend is running.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-100 grid grid-cols-1 lg:grid-cols-2 gap-8">
      
      {/* LEFT: FORM SECTION */}
      <form onSubmit={handleSubmit} className="space-y-4">
        <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2 border-b border-gray-100 pb-2 mb-4">
          <Calendar className="text-blue-600" size={20}/> Create New Event
        </h3>
        
        {error && (
            <div className="p-3 bg-red-50 text-red-600 text-sm rounded flex items-center gap-2">
                <AlertCircle size={16}/> {error}
            </div>
        )}

        <Input 
            label="Event Title" 
            name="title" 
            placeholder="e.g. Campus Clean Drive" 
            value={formData.title} 
            onChange={handleChange} 
            required 
        />

        <div>
          <label htmlFor="event-description" className="block text-sm font-medium text-gray-700 mb-1.5">Description</label>
          <textarea 
            id="event-description"
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-100 outline-none text-sm text-gray-900 bg-white"
            rows="2"
            name="description"
            value={formData.description}
            onChange={handleChange}
          />
        </div>

        <Input 
            label="Date" 
            type="date" 
            name="date" 
            value={formData.date} 
            onChange={handleChange} 
            required 
        />
        
        {/* Event Type */}
        <div>
          <label htmlFor="event-type" className="block text-sm font-medium text-gray-700 mb-1.5">Event Type</label>
          <select
            id="event-type"
            name="type"
            value={formData.type}
            onChange={handleChange}
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-100 outline-none text-sm text-gray-900 bg-white"
            required
          >
            <option value="Volunteer">Volunteer</option>
            <option value="Meeting">Meeting</option>
            <option value="Workshop">Workshop</option>
            <option value="Other">Other</option>
          </select>
        </div>
        
        {/* Geofence Inputs */}
        <div className="p-4 bg-blue-50 rounded-xl border border-blue-100 relative">
          <label className="block text-sm font-bold text-blue-800 mb-2 flex items-center gap-2">
            <MapPin size={16}/> Geofence Location (For Attendance)
          </label>
          
          <div className="grid grid-cols-2 gap-3 mb-3">
            <input 
              id="geofence-latitude"
              placeholder="Latitude" 
              className="p-2 text-xs rounded border border-blue-200 text-gray-900 bg-white"
              name="latitude"
              value={formData.latitude} 
              onChange={handleChange}
              required
            />
            <input 
              id="geofence-longitude"
              placeholder="Longitude" 
              className="p-2 text-xs rounded border border-blue-200 text-gray-900 bg-white"
              name="longitude"
              value={formData.longitude} 
              onChange={handleChange}
              required
            />
          </div>
          
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-2">
                <span className="text-xs text-blue-700">Radius (m):</span>
                <input 
                    type="number"
                    name="radius"
                    value={formData.radius}
                    onChange={handleChange}
                    className="w-16 p-1 text-xs border border-blue-200 rounded text-center text-gray-900 bg-white"
                />
            </div>
            <button 
                type="button" 
                onClick={getCurrentLocation}
                className="text-xs font-semibold text-white bg-blue-600 px-3 py-1.5 rounded hover:bg-blue-700 transition"
            >
                📍 Use Current Location
            </button>
          </div>
        </div>

        <Button type="submit" isLoading={loading} className="w-full py-3">
            Create Event & Generate QR
        </Button>
      </form>

      {/* RIGHT: QR CODE DISPLAY SECTION */}
      <div className="flex flex-col items-center justify-center border-l border-gray-100 pl-0 lg:pl-8 pt-8 lg:pt-0">
        {createdEventId ? (
          <div className="text-center animate-scale-up">
            <div className="mb-4 bg-green-50 text-green-700 px-4 py-2 rounded-full text-sm font-bold inline-block">
                Event Created Successfully!
            </div>
            
            <h4 className="font-bold text-gray-800 mb-4 text-lg">Scan for Attendance</h4>
            
            <div className="p-6 bg-white border-8 border-gray-900 rounded-3xl inline-block shadow-xl">
              {/* Generates QR containing ONLY the Event ID */}
              <QRCode 
                value={createdEventId} 
                size={200} 
                level="H" // High Error Correction
              />
            </div>
            
            <p className="text-xs text-gray-400 mt-6 font-mono bg-gray-50 p-2 rounded">
                ID: {createdEventId}
            </p>
            
            <button 
                onClick={() => window.print()} 
                className="mt-6 flex items-center gap-2 mx-auto text-sm text-blue-600 font-bold hover:bg-blue-50 px-4 py-2 rounded transition"
            >
                🖨️ Print QR Code
            </button>
          </div>
        ) : (
          <div className="text-center text-gray-300 flex flex-col items-center">
            <div className="w-32 h-32 bg-gray-50 rounded-2xl flex items-center justify-center mb-4">
                <QrCode size={64} className="opacity-20"/>
            </div>
            <p className="text-sm font-medium text-gray-400">QR Code will appear here<br/>after you create the event.</p>
          </div>
        )}
      </div>

    </div>
  );
};

