import React, { useState, useEffect, useContext } from 'react';
import Header from '../components/ui/Header';
import GamificationStatCard from '../components/ui/GamificationStatCard';
import StreakCard from '../components/ui/StreakCard';
import MeetingPreview from '../components/ui/MeetingPreview';
import ActivityFeed from '../components/gamification/ActivityFeed';
import BloodGroupSummary from '../components/ui/BloodGroupSummary';
import NoticeBoard from '../components/notices/NoticeBoard';
import BottomNav from '../components/layout/BottomNav';
import useBranding from '../hooks/useBranding';
import api from '../services/api';
import { AuthContext } from '../context/AuthContext';
import { CheckCircle, Clock, PlayCircle, Lock, Trophy, ClipboardList } from 'lucide-react';

const BentoDashboard = () => {
  const { user } = useContext(AuthContext);
  const { primaryColor } = useBranding();
  
  const xp = user?.gamification?.xpPoints || 0;
  const level = user?.gamification?.level || 1;
  const progressRatio = (xp % 100) / 100; // Example calc
  const [tasks, setTasks] = useState([]);
  const [taskLoading, setTaskLoading] = useState(true);
  const upcoming = { title: 'Unit Meeting', date: 'Dec 30', time: '17:00' };

  // --- EFFECTS ---
  useEffect(() => {
    fetchTasks();
  }, []);

  // --- ACTIONS ---
  const fetchTasks = async () => {
    try {
      const { data } = await api.get('/tasks');
      setTasks(Array.isArray(data) ? data : []);
      setTaskLoading(false);
    } catch (error) {
      console.error("Failed to fetch tasks:", error);
      setTasks([]);
      setTaskLoading(false);
    }
  };

  const handleClaim = async (id) => {
    try {
      await api.put(`/tasks/${id}/claim`);
      fetchTasks();
    } catch (err) { alert(err.response?.data?.message); }
  };

  const handleSubmit = async (id) => {
    try {
      await api.put(`/tasks/${id}/submit`, { submissionData: '' });
      fetchTasks();
    } catch (err) { alert(err.response?.data?.message); }
  };

  // --- HELPERS ---
  const pendingTasks = tasks.filter(t => t.status === 'Pending');
  const myTasks = tasks.filter(t => t.status === 'In Progress' && t.assignedUsers?.some(u => u._id === user?._id));
  const reviewTasks = tasks.filter(t => t.status === 'Completed');

  // --- SUB-COMPONENTS (Scoped to this dashboard) ---
  const TaskCard = ({ task }) => (
    <div className="bg-white p-2.5 rounded-lg shadow-sm border border-blue-200 mb-2 hover:shadow-md transition active:scale-95">
        <h4 className="font-bold text-xs text-blue-900 mb-1 line-clamp-1">{task.title}</h4>
        <p className="text-[10px] text-blue-600 mb-2 line-clamp-2">{task.description}</p>

        <div className="flex justify-between items-center gap-1">
            <span className="text-[10px] font-bold text-cyan-700 bg-cyan-50 px-2 py-0.5 rounded flex-shrink-0">
                +{task.xpReward || 20} XP
            </span>

            {/* Buttons */}
            {task.status === 'Pending' && (
                <button onClick={() => handleClaim(task._id)} className="text-[10px] bg-blue-700 text-white px-2 py-1 rounded hover:bg-blue-800 transition">
                    Claim
                </button>
            )}

            {task.status === 'In Progress' && task.assignedUsers?.some(u => u._id === user?._id) && (
                <button onClick={() => handleSubmit(task._id)} className="text-[10px] bg-cyan-600 text-white px-2 py-1 rounded hover:bg-cyan-700 transition">
                    Mark Done
                </button>
            )}

            {task.status === 'Completed' && (
                <span className="text-[10px] text-blue-600 flex items-center gap-1">
                    <Clock size={12}/> In Review
                </span>
            )}
        </div>
    </div>
  );

  return (
    <div className="min-h-screen text-blue-900 bg-[#f0f7ff]">
      <Header />

      <main className="max-w-6xl mx-auto px-4 py-8 pb-32">

        {/* TOP HERO SECTION */}
        <section className="mb-10">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 mb-2">
            <div>
              <h1 className="text-4xl font-black text-blue-700 tracking-tight leading-none">
                Volunteer <span className="text-cyan-600">Hub</span>
              </h1>
              <p className="text-blue-600 font-bold mt-2 uppercase tracking-widest text-[10px]">Your personal impact mission control</p>
            </div>
          </div>
        </section>

        {/* BENTO GRID */}
        <div className="grid grid-cols-1 md:grid-cols-12 gap-6">
          
          {/* STATS & PROGRESS (Left Column) */}
          <div className="md:col-span-4 space-y-6">
            <div className="transform hover:scale-[1.02] transition-transform duration-300">
              <GamificationStatCard 
                xp={xp} 
                level={level} 
                progress={progressRatio} 
              />
            </div>
            <div className="transform hover:scale-[1.02] transition-transform duration-300 shadow-xl shadow-blue-100">
              <StreakCard days={user?.gamification?.streak || 0} />
            </div>
            
            {/* QUICK STATS MINI-GRID */}
            <div className="grid grid-cols-2 gap-4">
              <BloodGroupSummary />
              <div className="bg-indigo-600 rounded-[2rem] p-5 text-white flex flex-col justify-between shadow-lg shadow-indigo-100">
                <div className="w-10 h-10 rounded-xl bg-white/20 flex items-center justify-center">
                  <Trophy size={20} />
                </div>
                <div>
                  <p className="text-[10px] font-black uppercase tracking-widest opacity-70">Global Rank</p>
                  <p className="text-2xl font-black tracking-tighter">#12</p>
                </div>
              </div>
            </div>
          </div>

          {/* MAIN CONTENT AREA (Right Column) */}
          <div className="md:col-span-8 flex flex-col gap-6">
            
            {/* UPCOMING & ACTIVITY */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="transform hover:scale-[1.01] transition-transform">
                  <MeetingPreview meeting={upcoming} />
                </div>
                <div className="bg-white rounded-[2.5rem] p-6 shadow-xl shadow-slate-200/50 border border-slate-100 flex flex-col h-full">
                   <h3 className="text-slate-900 font-black mb-6 flex items-center gap-2 text-xs uppercase tracking-[0.2em]">
                     <div className="w-2.5 h-2.5 bg-green-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(34,197,94,0.5)]"></div>
                     Live Activity
                   </h3>
                   <div className="flex-1 overflow-y-auto max-h-[160px] scrollbar-hide">
                     <ActivityFeed limit={4} />
                   </div>
                </div>
            </div>

            {/* NOTICE BOARD (Full Width in column) */}
            <div className="shadow-2xl shadow-indigo-900/5 rounded-[2.5rem] overflow-hidden">
              <NoticeBoard />
            </div>

          </div>
        </div>

        {/* TASK COMMAND SECTION */}
        <section className="mt-12">
            <div className="flex items-center justify-between mb-8 group">
                <div className="flex items-center gap-4">
                   <div className="w-12 h-12 rounded-2xl bg-blue-700 flex items-center justify-center text-white shadow-lg rotate-3 group-hover:rotate-0 transition-all duration-300">
                      <ClipboardList size={24} />
                   </div>
                   <div>
                      <h2 className="text-3xl font-black text-blue-900 tracking-tighter">Mission Control</h2>
                      <p className="text-blue-500 font-bold text-[10px] uppercase tracking-widest">Active task deployments</p>
                   </div>
                </div>
                <div className="flex items-center gap-2">
                    <span className="h-2 w-2 rounded-full bg-cyan-600 animate-ping"></span>
                    <span className="bg-cyan-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full shadow-lg shadow-cyan-200 uppercase tracking-widest">
                        {tasks.length} Operations Active
                    </span>
                </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                
                {/* 1. AVAILABLE - "THE OPPORTUNITIES" */}
                <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 min-h-[400px] shadow-xl shadow-slate-200/50">
                    <h3 className="font-black text-slate-900 mb-6 flex items-center gap-3 text-xs uppercase tracking-[0.2em] opacity-50">
                        <Lock size={16} className="text-slate-400" /> New Missions
                    </h3>
                    <div className="space-y-4">
                        {pendingTasks.length === 0 && (
                          <div className="py-20 text-center opacity-20">
                            <Lock size={40} className="mx-auto mb-2" />
                            <p className="text-sm font-bold uppercase">Locked</p>
                          </div>
                        )}
                        {pendingTasks.map(task => <TaskCard key={task._id} task={task} />)}
                    </div>
                </div>

                {/* 2. IN PROGRESS - "ACTIVE DUTY" */}
                <div className="bg-slate-900 p-6 rounded-[2.5rem] min-h-[400px] shadow-2xl shadow-slate-900/20 relative overflow-hidden group">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/10 rounded-full blur-3xl group-hover:bg-blue-600/20 transition-all duration-700"></div>
                    <h3 className="font-black text-blue-400 mb-6 flex items-center gap-3 text-xs uppercase tracking-[0.2em] relative z-10">
                        <PlayCircle size={16} /> Active Operations
                    </h3>
                    <div className="space-y-4 relative z-10">
                        {myTasks.length === 0 && (
                           <div className="py-20 text-center opacity-30">
                             <PlayCircle size={40} className="mx-auto mb-2 text-blue-600" />
                             <p className="text-sm font-bold uppercase text-white">Stand By</p>
                           </div>
                        )}
                        {myTasks.map(task => <TaskCard key={task._id} task={task} />)}
                    </div>
                </div>

                {/* 3. UNDER REVIEW - "DEBRIEFING" */}
                <div className="bg-[#f1f5f9] p-6 rounded-[2.5rem] border border-slate-200 min-h-[400px] shadow-inner">
                    <h3 className="font-black text-slate-400 mb-6 flex items-center gap-3 text-xs uppercase tracking-[0.2em]">
                        <CheckCircle size={16} /> Data Verification
                    </h3>
                    <div className="space-y-4">
                        {reviewTasks.length === 0 && (
                           <div className="py-20 text-center opacity-20">
                             <CheckCircle size={40} className="mx-auto mb-2" />
                             <p className="text-sm font-bold uppercase">Clean Slate</p>
                           </div>
                        )}
                        {reviewTasks.map(task => <TaskCard key={task._id} task={task} />)}
                    </div>
                </div>

            </div>
        </section>

      </main>

      <BottomNav />
    </div>
  );
};

export default BentoDashboard;

import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link } from 'react-router-dom';
import api from '../services/api';
import Layout from '../components/layout/Layout';
import Loader from '../components/common/Loader';
import { AuthContext } from '../context/AuthContext';
import { toast } from 'react-hot-toast';

// --- Discussion Component ---
const EventDiscussion = ({ eventId }) => {
  const { user } = useContext(AuthContext);
  const [posts, setPosts] = useState([]);
  const [newPostContent, setNewPostContent] = useState('');
  const [loading, setLoading] = useState(true);

  const fetchPosts = async () => {
    try {
      const { data } = await api.get(`/discussions/${eventId}`);
      setPosts(data);
    } catch (error) {
      console.error("Failed to fetch discussion posts", error);
      toast.error("Failed to load discussion.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (eventId) {
      fetchPosts();
    }
  }, [eventId]);

  const handlePostSubmit = async (e) => {
    e.preventDefault();
    if (!newPostContent.trim()) return;

    try {
      await api.post(`/discussions/${eventId}`, { content: newPostContent });
      setNewPostContent('');
      toast.success('Your message has been posted!');
      fetchPosts(); // Refresh posts
    } catch (error) {
      toast.error("Failed to post message.");
      console.error("Failed to create post", error);
    }
  };

  const Post = ({ post }) => (
    <div className="flex items-start gap-3 mb-4">
      <img src={post.userId.profileImage || '/placeholder-logo.svg'} alt={post.userId.name} className="w-10 h-10 rounded-full object-cover" />
      <div className="flex-1 bg-gray-100 p-3 rounded-lg">
        <div className="flex items-center justify-between">
          <span className="font-bold text-sm">{post.userId.name}</span>
          <span className="text-xs text-gray-500">{new Date(post.createdAt).toLocaleTimeString()}</span>
        </div>
        <p className="text-sm mt-1">{post.content}</p>
      </div>
    </div>
  );

  if (loading) return <Loader />;

  return (
    <div className="mt-8">
      <h3 className="text-xl font-bold mb-4">Discussion</h3>
      <div className="space-y-4 mb-6">
        {posts.length > 0 ? posts.map(post => <Post key={post._id} post={post} />) : <p className="text-gray-500">No discussion yet. Be the first to comment!</p>}
      </div>
      <form onSubmit={handlePostSubmit} className="flex gap-2">
        <input
          type="text"
          value={newPostContent}
          onChange={(e) => setNewPostContent(e.target.value)}
          placeholder="Ask a question or leave a comment..."
          className="flex-1 p-2 border rounded-lg"
        />
        <button type="submit" className="px-4 py-2 bg-blue-600 text-white rounded-lg font-semibold">Post</button>
      </form>
    </div>
  );
};


// --- Main Event Details Page ---
const EventDetails = () => {
  const { id } = useParams();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchEvent = async () => {
      try {
        const { data } = await api.get(`/events/${id}`);
        setEvent(data);
      } catch (err) {
        setError('Failed to fetch event details.');
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchEvent();
  }, [id]);

  if (loading) {
    return <Layout><Loader /></Layout>;
  }

  if (error || !event) {
    return <Layout><div className="text-red-500 text-center p-8">{error || 'Event not found.'}</div></Layout>;
  }

  return (
    <Layout showBackButton={true}>
      <div className="max-w-4xl mx-auto p-4">
        <h1 className="text-3xl font-bold mb-2">{event.name}</h1>
        <div className="text-gray-500 mb-4">
          <span>{new Date(event.date).toDateString()}</span> | <span>{event.location || 'Online'}</span>
        </div>
        <p className="mb-6">{event.description}</p>

        <div className="border-t border-gray-200 pt-6">
          <EventDiscussion eventId={event._id} />
        </div>
      </div>
    </Layout>
  );
};

export default EventDetails;

import React, { useState, useEffect, useContext } from 'react';
import Layout from '../components/layout/Layout';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';
import { Heart, Activity, MapPin, AlertCircle, Send } from 'lucide-react';
import useGeoLocation from '../hooks/useGeoLocation';

const ImpactHub = () => {
  const { user } = useContext(AuthContext);
  const { location, getLocation } = useGeoLocation();
  const [activeTab, setActiveTab] = useState('sos'); // 'sos' or 'wall'
  const [sosLoading, setSosLoading] = useState(false);
  
  // SOS Form State
  const [sosData, setSosData] = useState({
    bloodType: 'O+',
    unitsNeeded: 1,
    recipientInfo: '',
    contactName: user?.name || '',
    contactPhone: user?.whatsappNumber || '',
  });

  const handleSOSSubmit = async (e) => {
    e.preventDefault();
    if (!location) {
      alert("Please enable GPS location first");
      getLocation();
      return;
    }
    
    setSosLoading(true);
    try {
      await api.post('/impact/sos/create', {
        ...sosData,
        location: {
          latitude: location.latitude,
          longitude: location.longitude,
          address: "Current Location" 
        },
        contactPerson: {
          name: sosData.contactName,
          phone: sosData.contactPhone
        }
      });
      alert("🚨 SOS Broadcast Sent to all nearby volunteers!");
      setSosData({ ...sosData, recipientInfo: '' }); // Reset
    } catch (error) {
      alert("Failed to send SOS: " + error.response?.data?.message);
    } finally {
      setSosLoading(false);
    }
  };

  return (
    <Layout userRole={user?.role}>
      <div className="max-w-4xl mx-auto p-4">
        <h1 className="text-3xl font-black text-gray-800 mb-6 flex items-center gap-3">
          <Heart className="text-red-600" fill="currentColor" /> Impact Hub
        </h1>

        {/* Tabs */}
        <div className="flex gap-4 mb-6">
          <button 
            onClick={() => setActiveTab('sos')}
            className={`flex-1 py-3 rounded-xl font-bold transition ${activeTab === 'sos' ? 'bg-red-600 text-white shadow-lg' : 'bg-white text-gray-600'}`}
          >
            🚨 Emergency SOS
          </button>
          <button 
            onClick={() => setActiveTab('wall')}
            className={`flex-1 py-3 rounded-xl font-bold transition ${activeTab === 'wall' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white text-gray-600'}`}
          >
            🧱 Wall of Kindness
          </button>
        </div>

        {/* SOS SECTION */}
        {activeTab === 'sos' && (
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-red-100">
            <div className="bg-red-50 p-4 rounded-xl mb-6 flex items-start gap-3">
              <AlertCircle className="text-red-600 shrink-0" />
              <p className="text-sm text-red-800">
                <strong>Emergency Broadcast:</strong> This will send a push notification to all volunteers with the matching blood type within 10km.
              </p>
            </div>

            <form onSubmit={handleSOSSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Blood Type</label>
                  <select 
                    value={sosData.bloodType}
                    onChange={(e) => setSosData({...sosData, bloodType: e.target.value})}
                    className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200"
                  >
                    {['O+', 'O-', 'A+', 'A-', 'B+', 'B-', 'AB+', 'AB-'].map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Units Needed</label>
                  <input 
                    type="number" 
                    value={sosData.unitsNeeded}
                    onChange={(e) => setSosData({...sosData, unitsNeeded: e.target.value})}
                    className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">Recipient Details (Hospital/Patient)</label>
                <textarea 
                  required
                  value={sosData.recipientInfo}
                  onChange={(e) => setSosData({...sosData, recipientInfo: e.target.value})}
                  className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 h-24"
                  placeholder="Ex: Patient Amit Kumar at City Hospital, Room 302. Urgent surgery."
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <input 
                  type="text" placeholder="Contact Name"
                  value={sosData.contactName}
                  onChange={(e) => setSosData({...sosData, contactName: e.target.value})}
                  className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200"
                />
                <input 
                  type="tel" placeholder="Phone Number"
                  value={sosData.contactPhone}
                  onChange={(e) => setSosData({...sosData, contactPhone: e.target.value})}
                  className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200"
                />
              </div>

              {!location && (
                <button type="button" onClick={getLocation} className="w-full py-3 bg-gray-200 text-gray-700 rounded-xl font-bold flex items-center justify-center gap-2">
                  <MapPin size={20} /> Enable Location to Send
                </button>
              )}

              {location && (
                <button 
                  type="submit" 
                  disabled={sosLoading}
                  className="w-full py-4 bg-red-600 text-white rounded-xl font-black text-lg shadow-xl hover:bg-red-700 transition active:scale-95 flex items-center justify-center gap-2"
                >
                  {sosLoading ? "Broadcasting..." : "BROADCAST SOS ALERT"}
                </button>
              )}
            </form>
          </div>
        )}

        {/* WALL OF KINDNESS PLACEHOLDER */}
        {activeTab === 'wall' && (
          <div className="text-center py-20 bg-white rounded-2xl">
            <Activity size={48} className="mx-auto text-gray-300 mb-4" />
            <h3 className="text-xl font-bold text-gray-400">Coming Soon</h3>
            <p className="text-gray-400">Share your volunteer stories here.</p>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default ImpactHub;

import React, { useState, useEffect, useContext } from 'react';
import { Search, BookOpen, HelpCircle, FileText, Video, Download } from 'lucide-react';
import Layout from '../components/layout/Layout';
import Navbar from '../components/layout/Navbar';
import api from '../services/api';
import { AuthContext } from '../context/AuthContext';

const KnowledgeBase = () => {
  const { user } = useContext(AuthContext);
  const [articles, setArticles] = useState([]);
  const [selectedArticle, setSelectedArticle] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [loading, setLoading] = useState(true);

  const categories = [
    { name: 'all', label: 'All Articles', icon: BookOpen },
    { name: 'Getting Started', label: 'Getting Started', icon: HelpCircle },
    { name: 'Guidelines', label: 'Guidelines', icon: FileText },
    { name: 'Procedures', label: 'Procedures', icon: FileText },
    { name: 'FAQ', label: 'FAQ', icon: HelpCircle },
    { name: 'Resources', label: 'Resources', icon: Download },
  ];

  useEffect(() => {
    fetchArticles();
  }, [selectedCategory, searchQuery]);

  const fetchArticles = async () => {
    try {
      setLoading(true);
      let url = '/knowledge-base';
      if (selectedCategory !== 'all') {
        url = `/knowledge-base/category/${selectedCategory}`;
      } else if (searchQuery) {
        url = `/knowledge-base/search/${searchQuery}`;
      }
      const response = await api.get(url);
      setArticles(response.data.data);
    } catch (error) {
      console.error('Failed to fetch articles:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleArticleSelect = async (article) => {
    try {
      const response = await api.get(`/knowledge-base/${article.slug}`);
      setSelectedArticle(response.data.data);
    } catch (error) {
      console.error('Failed to fetch article:', error);
    }
  };

  const handleMarkHelpful = async (helpful) => {
    try {
      await api.put(`/knowledge-base/${selectedArticle.slug}/helpful`, { helpful });
      alert(helpful ? 'Thanks for finding this helpful!' : 'Thanks for the feedback');
    } catch (error) {
      console.error('Failed to mark helpful:', error);
    }
  };

  return (
    <Layout showBackButton={true}>
      
      <div className="max-w-6xl mx-auto p-4 sm:p-6">
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-800 mb-2 flex items-center gap-2">
            <BookOpen size={32} className="text-blue-600" />
            Knowledge Base
          </h1>
          <p className="text-gray-600">Find answers and learn how to get the most out of the application</p>
        </div>

        {/* Search Bar */}
        <div className="mb-6">
          <div className="relative">
            <Search className="absolute left-4 top-3 text-gray-400" size={20} />
            <input
              type="text"
              placeholder="Search articles, guides, and FAQs..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-12 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
        </div>

        {/* Categories */}
        <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
          {categories.map(({ name, label, icon: Icon }) => (
            <button
              key={name}
              onClick={() => setSelectedCategory(name)}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg whitespace-nowrap font-medium transition ${
                selectedCategory === name
                  ? 'bg-blue-600 text-white'
                  : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-50'
              }`}
            >
              <Icon size={18} />
              {label}
            </button>
          ))}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Articles List */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-lg shadow-md overflow-hidden">
              <div className="p-4 bg-gray-100 border-b">
                <h2 className="font-bold text-gray-800">
                  {selectedCategory === 'all' ? 'All Articles' : selectedCategory}
                </h2>
                <p className="text-sm text-gray-600">{articles.length} articles</p>
              </div>

              {loading ? (
                <div className="p-4 text-center text-gray-500">Loading...</div>
              ) : (
                <div className="max-h-96 overflow-y-auto">
                  {articles.map((article) => (
                    <button
                      key={article._id}
                      onClick={() => handleArticleSelect(article)}
                      className={`w-full text-left p-4 border-b hover:bg-gray-50 transition ${
                        selectedArticle?._id === article._id ? 'bg-blue-50 border-l-4 border-l-blue-600' : ''
                      }`}
                    >
                      <h3 className="font-medium text-gray-800 text-sm">{article.title}</h3>
                      <p className="text-xs text-gray-500 mt-1">{article.views} views</p>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Article Content */}
          <div className="lg:col-span-2">
            {selectedArticle ? (
              <div className="bg-white rounded-lg shadow-md p-6">
                <div className="mb-6">
                  <span className="inline-block bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-xs font-semibold mb-3">
                    {selectedArticle.category}
                  </span>
                  <h1 className="text-3xl font-bold text-gray-800 mb-2">{selectedArticle.title}</h1>
                  <p className="text-gray-600">{selectedArticle.description}</p>
                </div>

                {selectedArticle.videoUrl && (
                  <div className="mb-6 bg-black rounded-lg overflow-hidden h-64 sm:h-96 flex items-center justify-center">
                    <Video size={48} className="text-gray-400" />
                    {/* Replace with actual video player */}
                  </div>
                )}

                <div className="prose max-w-none mb-6">
                  <div className="text-gray-700 leading-relaxed whitespace-pre-wrap">{selectedArticle.content}</div>
                </div>

                {selectedArticle.attachments && selectedArticle.attachments.length > 0 && (
                  <div className="mb-6 border-t pt-6">
                    <h3 className="font-bold text-gray-800 mb-3">Attachments</h3>
                    <div className="space-y-2">
                      {selectedArticle.attachments.map((attachment, idx) => (
                        <a
                          key={idx}
                          href={attachment.fileUrl}
                          className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg hover:bg-gray-100 transition"
                        >
                          <Download size={18} className="text-blue-600" />
                          <span className="text-sm font-medium text-gray-700">{attachment.fileName}</span>
                        </a>
                      ))}
                    </div>
                  </div>
                )}

                {/* Helpful Section */}
                <div className="border-t pt-6 mt-6">
                  <p className="text-sm text-gray-600 mb-3">Was this article helpful?</p>
                  <div className="flex gap-3">
                    <button
                      onClick={() => handleMarkHelpful(true)}
                      className="flex items-center gap-2 px-4 py-2 bg-green-100 text-green-700 rounded-lg hover:bg-green-200 transition font-medium"
                    >
                      👍 Yes
                    </button>
                    <button
                      onClick={() => handleMarkHelpful(false)}
                      className="flex items-center gap-2 px-4 py-2 bg-red-100 text-red-700 rounded-lg hover:bg-red-200 transition font-medium"
                    >
                      👎 No
                    </button>
                  </div>
                </div>
              </div>
            ) : (
              <div className="bg-white rounded-lg shadow-md p-12 text-center">
                <BookOpen size={48} className="mx-auto text-gray-300 mb-4" />
                <p className="text-gray-500">Select an article to read</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default KnowledgeBase;

import React, { useState, useContext, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { Mail, Lock, LogIn, Loader2, Eye, EyeOff } from 'lucide-react';
import StreakModal from '../components/modals/StreakModal';


const Login = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [showStreak, setShowStreak] = useState(false);
  const [newStreakCount, setNewStreakCount] = useState(0);
  
  const [rememberMe, setRememberMe] = useState(true);
  const [showPassword, setShowPassword] = useState(false);
  
  const { login, loading, user } = useContext(AuthContext);
  const [error, setError] = useState(null);
  const navigate = useNavigate();

  const getRedirectPath = (role) => {
    const r = role?.toLowerCase();
    if (r === 'secretary') return '/secretary/dashboard';
    if (r === 'domain head') return '/domain-head/dashboard';
    if (r === 'associate head') return '/associate-head/dashboard';
    return '/volunteer/dashboard';
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);
    
    // Try to login with remember me flag
    const result = await login(formData.email, formData.password, rememberMe);
    
    if (result && result.success && result.user) {
      // Check if streak increased
      if (result.user.gamification?.streak > 0) {
        setNewStreakCount(result.user.gamification.streak);
        setShowStreak(true);
      } else {
        navigate(getRedirectPath(result.user.role));
      }
    } else if (result && !result.success) {
      setError(result.message || 'Login failed');
    }
  };

  const handleCloseStreak = () => {
    setShowStreak(false);
    navigate(getRedirectPath(user?.role));
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center px-3 sm:px-6 py-8 sm:py-12 animate-in fade-in duration-700">
      
      {/* STREAK ALERT POPUP */}
      {showStreak && (
        <StreakModal 
          streak={newStreakCount} 
          onClose={handleCloseStreak} 
        />
      )}

      <div className="sm:mx-auto sm:w-full sm:max-w-md">
        <div className="w-24 sm:w-32 h-24 sm:h-32 mx-auto mb-4 sm:mb-6 transform hover:rotate-6 transition-transform duration-500">
          <img src="/logo.png" alt="NSS Logo" className="w-full h-full object-contain filter drop-shadow-2xl" />
        </div>
        <h2 className="text-center text-3xl sm:text-4xl font-black text-slate-900 tracking-tighter">
          Welcome <span className="text-blue-600">Back</span>
        </h2>
        <p className="mt-2 text-center text-[10px] sm:text-xs text-slate-400 font-black uppercase tracking-[0.3em]">
          Operational Mission Access
        </p>
      </div>

      <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
        <div className="bg-white py-10 px-6 sm:px-12 shadow-2xl shadow-slate-900/5 border border-slate-100 rounded-[3rem]">
          <form className="space-y-6" onSubmit={handleSubmit}>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1 mb-2">
                Email
             </label>
              <div className="relative group">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-600 transition-colors" size={18} />
                <input
                  type="email"
                  required
                  className="w-full pl-12 pr-4 py-4 bg-slate-50 border-2 border-transparent rounded-[1.5rem] focus:bg-white focus:border-blue-600/20 focus:ring-4 focus:ring-blue-600/5 font-bold text-slate-800 transition-all outline-none"
                  placeholder="name@college.edu"
                  value={formData.email}
                  onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                />
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1 mb-2">
                Password
              </label>
              <div className="relative group">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-blue-600 transition-colors" size={18} />
                <input
                  type={showPassword ? "text" : "password"}
                  required
                  className="w-full pl-12 pr-12 py-4 bg-slate-50 border-2 border-transparent rounded-[1.5rem] focus:bg-white focus:border-blue-600/20 focus:ring-4 focus:ring-blue-600/5 font-bold text-slate-800 transition-all outline-none"
                  placeholder="••••••••"
                  value={formData.password}
                  onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-blue-600 transition-colors focus:outline-none"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            {/* STAY SIGNED IN TOGGLE */}
            <div className="flex items-center justify-between px-1">
               <label className="flex items-center cursor-pointer group">
                  <div className="relative">
                    <input 
                      type="checkbox" 
                      className="sr-only" 
                      checked={rememberMe}
                      onChange={() => setRememberMe(!rememberMe)}
                    />
                    <div className={`w-10 h-5 rounded-full transition-colors duration-300 ${rememberMe ? 'bg-blue-600' : 'bg-slate-200'}`}></div>
                    <div className={`absolute left-0.5 top-0.5 bg-white w-4 h-4 rounded-full shadow-md transition-transform duration-300 transform ${rememberMe ? 'translate-x-5' : 'translate-x-0'}`}></div>
                  </div>
                  <span className="ml-3 text-[10px] font-black text-slate-400 uppercase tracking-widest group-hover:text-slate-600 transition-colors">Stay signed in</span>
               </label>
               <Link to="/forgot-password" size="sm" className="text-[10px] font-black text-blue-600 uppercase tracking-widest hover:text-slate-900 transition-colors">
                 Forgot Password
               </Link>
            </div>

            {error && (
              <div className="bg-red-50 text-red-600 p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-red-100 flex items-center gap-3 animate-shake">
                <span className="w-2 h-2 rounded-full bg-red-600"></span>
                {error}
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full flex justify-center items-center gap-3 py-5 px-4 rounded-[1.5rem] shadow-xl shadow-blue-600/20 text-[10px] font-black uppercase tracking-[0.3em] text-white bg-blue-600 hover:bg-slate-900 focus:outline-none transition-all active:scale-95 disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin" size={20} /> : <LogIn size={18} />}
              <span>{loading ? 'Authenticating...' : 'Log In'}</span>
            </button>
          </form>

          <div className="mt-6 sm:mt-8 text-center">
            <p className="text-xs sm:text-sm text-gray-500">
              Don't have an account?{' '}
              <Link to="/register" className="font-black text-blue-600 hover:text-blue-500">
                Register here
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

