import React, { useState, useEffect } from 'react';
import Layout from '../components/layout/Layout';
import api from '../services/api';
import Loader from '../components/common/Loader';
import { toast } from 'react-hot-toast';

const Polls = () => {
  const [polls, setPolls] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchPolls = async () => {
    try {
      setLoading(true);
      const { data } = await api.get('/polls');
      setPolls(data);
      setLoading(false);
    } catch (err) {
      setError('Failed to fetch polls.');
      toast.error('Failed to fetch polls.');
      setLoading(false);
      console.error(err);
    }
  };

  useEffect(() => {
    fetchPolls();
  }, []);

  const vote = async (pollId, optionId) => {
    try {
      await api.post(`/polls/${pollId}/vote`, { optionId });
      toast.success('Vote submitted successfully!');
      fetchPolls(); // Refresh to show updated results
    } catch (error) {
      toast.error('Failed to submit vote.');
      console.error(error);
    }
  };

  const hasVoted = (poll) => {
    return poll.votes?.some(vote => vote.user.toString() === localStorage.getItem('userId'));
  };

  const getTotalVotes = (poll) => {
    return poll.options.reduce((total, option) => total + (option.votes || 0), 0);
  };

  if (loading) return <Layout><Loader /></Layout>;
  if (error) return <Layout><div className="text-red-500 text-center">{error}</div></Layout>;

  return (
    <Layout>
      <div className="max-w-4xl mx-auto p-6">
        <h1 className="text-3xl font-bold mb-6">Polls</h1>

        <div className="space-y-6">
          {polls.length === 0 ? (
            <div className="text-center text-gray-500 py-8">
              No polls available.
            </div>
          ) : (
            polls.map(poll => (
              <div key={poll._id} className="bg-white border rounded-lg p-6 shadow-sm">
                <h2 className="text-2xl font-semibold mb-4">{poll.question}</h2>
                <p className="text-gray-600 mb-4">{poll.description}</p>

                <div className="space-y-3">
                  {poll.options.map(option => {
                    const percentage = getTotalVotes(poll) > 0 ? ((option.votes || 0) / getTotalVotes(poll)) * 100 : 0;
                    const userVoted = hasVoted(poll);

                    return (
                      <div key={option._id} className="relative">
                        <button
                          onClick={() => !userVoted && vote(poll._id, option._id)}
                          disabled={userVoted}
                          className={`w-full text-left p-3 border rounded-lg transition-colors ${
                            userVoted ? 'cursor-not-allowed bg-gray-100' : 'hover:bg-gray-50'
                          }`}
                        >
                          <div className="flex justify-between items-center">
                            <span>{option.text}</span>
                            {userVoted && (
                              <span className="text-sm text-gray-500">
                                {option.votes || 0} votes ({percentage.toFixed(1)}%)
                              </span>
                            )}
                          </div>
                        </button>
                        {userVoted && (
                          <div
                            className="absolute bottom-0 left-0 h-1 bg-blue-500 rounded-b-lg transition-all duration-300"
                            style={{ width: `${percentage}%` }}
                          />
                        )}
                      </div>
                    );
                  })}
                </div>

                <div className="mt-4 text-sm text-gray-500">
                  Total votes: {getTotalVotes(poll)} • {hasVoted(poll) ? 'You have voted' : 'Click an option to vote'}
                </div>
                <div className="text-xs text-gray-400 mt-1">
                  Created: {new Date(poll.createdAt).toLocaleDateString()}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </Layout>
  );
};

export default Polls;

import React, { useState, useEffect, useContext } from 'react';
import Layout from '../components/layout/Layout';
import { AuthContext } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import api from '../services/api';
import { Sun, Bell, Lock, LogOut } from 'lucide-react';

// --- ADMIN COMPONENTS (Crucial for SaaS features) ---
import SecretaryCustomizer from '../components/digital-id/SecretaryCustomizer';
import SessionManager from '../components/admin/SessionManager';

const Settings = () => {
  const { user, logout, updateUser } = useContext(AuthContext);
  const { theme, updateTheme } = useTheme();
  const [preferences, setPreferences] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [notification, setNotification] = useState(null);
  const [isEditProfileModalOpen, setIsEditProfileModalOpen] = useState(false);
  const [newName, setNewName] = useState('');
  const [bloodGroup, setBloodGroup] = useState('');
  const [oldPassword, setOldPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  useEffect(() => {
    fetchPreferences();
    if (user) {
      setNewName(user.name);
      setBloodGroup(user.bloodGroup || '');
    }
  }, [user]);

  const fetchPreferences = async () => {
    try {
      const { data } = await api.get('/preferences');
      setPreferences(data.data);
    } catch (error) {
      console.error('Failed to fetch preferences:', error);
      // Set defaults if fetch fails
      setPreferences({
        theme: 'light',
        language: 'en',
        notifications: {
          activityFeed: true,
          polls: true,
          announcements: true,
          taskReminders: true,
          achievements: true,
          email: false,
          push: true
        },
        privacy: {
          showProfile: true,
          showActivity: true,
          showStats: true,
          allowMessages: true
        }
      });
    } finally {
      setLoading(false);
    }
  };

  const handleChangePassword = async () => {
    if (newPassword !== confirmPassword) {
      showNotification('New passwords do not match', 'error');
      return;
    }
    if (newPassword.length < 6) {
      showNotification('Password must be at least 6 characters long', 'error');
      return;
    }
    setSaving(true);
    try {
      await api.put('/auth/change-password', { oldPassword, newPassword });
      showNotification('Password updated successfully', 'success');
      setOldPassword('');
      setNewPassword('');
      setConfirmPassword('');
    } catch (error) {
      showNotification(error.response?.data?.message || 'Failed to update password', 'error');
    } finally {
      setSaving(false);
    }
  };

  const handleUpdateProfile = async () => {
    setSaving(true);
    try {
      const { data } = await api.put('/users/profile', { name: newName, bloodGroup });
      updateUser(data); // Update user in AuthContext
      showNotification('Profile updated successfully', 'success');
      setIsEditProfileModalOpen(false);
    } catch (error) {
      showNotification('Failed to update profile', 'error');
    } finally {
      setSaving(false);
    }
  };

  const handleThemeChange = async (newTheme) => {
    setSaving(true);
    try {
      await api.put('/preferences/theme', { theme: newTheme });
      updateTheme(newTheme);
      setPreferences(prev => ({ ...prev, theme: newTheme }));
      showNotification('Theme updated successfully', 'success');
    } catch (error) {
      showNotification('Failed to update theme', 'error');
    } finally {
      setSaving(false);
    }
  };

  const handleLanguageChange = async (newLanguage) => {
    setSaving(true);
    try {
      await api.put('/preferences/language', { language: newLanguage });
      setPreferences(prev => ({ ...prev, language: newLanguage }));
      showNotification('Language updated successfully', 'success');
    } catch (error) {
      showNotification('Failed to update language', 'error');
    } finally {
      setSaving(false);
    }
  };

  const handleNotificationToggle = async (type, checked) => {
    setSaving(true);
    try {
      const updated = {
        ...preferences.notifications,
        [type]: checked
      };
      await api.put('/preferences/notifications', { notifications: updated });
      setPreferences(prev => ({
        ...prev,
        notifications: updated
      }));
      showNotification('Notification preferences updated', 'success');
    } catch (error) {
      showNotification('Failed to update notifications', 'error');
    } finally {
      setSaving(false);
    }
  };

  const handlePrivacyToggle = async (type, checked) => {
    setSaving(true);
    try {
      const updated = {
        ...preferences.privacy,
        [type]: checked
      };
      await api.put('/preferences/privacy', { privacy: updated });
      setPreferences(prev => ({
        ...prev,
        privacy: updated
      }));
      showNotification('Privacy settings updated', 'success');
    } catch (error) {
      showNotification('Failed to update privacy settings', 'error');
    } finally {
      setSaving(false);
    }
  };

  const handleLogout = () => {
    if (window.confirm('Are you sure you want to logout?')) {
      logout();
    }
  };

  const showNotification = (message, type) => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  if (loading) {
    return (
      <Layout showBackButton={true}>
        <div className="flex justify-center items-center h-64">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout showBackButton={true}>
      
      <div className="max-w-2xl mx-auto pb-10">
        {/* Notification Toast */}
        {notification && (
          <div className={`fixed top-4 right-4 p-4 rounded-lg text-white z-50 ${
            notification.type === 'success' ? 'bg-green-500' : 'bg-red-500'
          }`}>
            {notification.message}
          </div>
        )}

        {/* Edit Profile Modal */}
        {isEditProfileModalOpen && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
            <div className="bg-white rounded-xl p-6 w-full max-w-md">
              <h2 className="text-lg font-bold mb-4">Edit Profile</h2>
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">Name</label>
                <input
                  type="text"
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  className="w-full p-2 border rounded-md"
                />
              </div>
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">Blood Group</label>
                <select
                  value={bloodGroup}
                  onChange={(e) => setBloodGroup(e.target.value)}
                  className="w-full p-2 border rounded-md"
                >
                  <option value="">Not Set</option>
                  <option value="A+">A+</option>
                  <option value="A-">A-</option>
                  <option value="B+">B+</option>
                  <option value="B-">B-</option>
                  <option value="AB+">AB+</option>
                  <option value="AB-">AB-</option>
                  <option value="O+">O+</option>
                  <option value="O-">O-</option>
                </select>
              </div>
              <div className="flex justify-end gap-2">
                <button onClick={() => setIsEditProfileModalOpen(false)} className="px-4 py-2 rounded-md text-sm font-medium bg-gray-200">Cancel</button>
                <button onClick={handleUpdateProfile} disabled={saving} className="px-4 py-2 rounded-md text-sm font-medium bg-blue-600 text-white disabled:opacity-50">
                  {saving ? 'Saving...' : 'Save'}
                </button>
              </div>
            </div>
          </div>
        )}

        <h1 className="text-3xl font-bold text-gray-800 mb-8">Settings</h1>

        {/* Appearance Settings */}
        <div className="bg-white rounded-xl shadow-sm p-6 mb-6">
          <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
            <Sun size={24} className="text-yellow-500" />
            Appearance
          </h2>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-3">Theme</label>
              <div className="flex gap-3 flex-wrap">
                {['light', 'dark', 'nss-blue'].map(t => (
                  <button
                    key={t}
                    onClick={() => handleThemeChange(t)}
                    disabled={saving}
                    className={`px-4 py-2 rounded-lg font-medium transition ${
                      preferences.theme === t
                        ? 'bg-blue-600 text-white'
                        : 'bg-gray-200 text-gray-800 hover:bg-gray-300'
                    } ${saving ? 'opacity-50 cursor-not-allowed' : ''}`}
                  >
                    {t === 'light' && '☀️'} {t === 'dark' && '🌙'} {t === 'nss-blue' && '🔵'}
                    {' '} {t.charAt(0).toUpperCase() + t.slice(1)}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-3">Language</label>
              <select
                value={preferences.language}
                onChange={(e) => handleLanguageChange(e.target.value)}
                disabled={saving}
                className="w-full p-3 text-black border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-600"
              >
                <option value="en">English</option>
                <option value="hi">हिन्दी (Hindi)</option>
              </select>
            </div>
          </div>
        </div>

        {/* ----------------------------------------------------------- */}
        {/* 🚀 ADMIN ZONES (Only visible to Secretary)                  */}
        {/* ----------------------------------------------------------- */}
        {user?.role === 'Secretary' && (
          <div className="space-y-6 mb-6">
            {/* 1. Branding Customizer (White-Label) */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <h3 className="text-xl font-bold text-purple-700 mb-4">Organization Branding</h3>
              <SecretaryCustomizer userSample={user} />
            </div>
            
            {/* 2. Session Manager (End Year / Handover) */}
            <SessionManager />
          </div>
        )}
        {/* ----------------------------------------------------------- */}

        {/* Notification Settings */}
        <div className="bg-white rounded-xl shadow-sm p-6 mb-6">
          <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
            <Bell size={24} className="text-blue-500" />
            Notifications
          </h2>

          <div className="space-y-4">
            {Object.entries(preferences.notifications).map(([key, value]) => (
              <div key={key} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                <label className="text-gray-800 font-medium capitalize">
                  {key.replace(/([A-Z])/g, ' $1').trim()}
                </label>
                <input
                  type="checkbox"
                  checked={value}
                  onChange={(e) => handleNotificationToggle(key, e.target.checked)}
                  disabled={saving}
                  className="w-5 h-5 cursor-pointer"
                />
              </div>
            ))}
          </div>
        </div>

        {/* Privacy Settings */}
        <div className="bg-white rounded-xl shadow-sm p-6 mb-6">
          <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
            <Lock size={24} className="text-red-500" />
            Privacy
          </h2>

          <div className="space-y-4">
            {Object.entries(preferences.privacy).map(([key, value]) => (
              <div key={key} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                <label className="text-gray-800 font-medium capitalize">
                  {key.replace(/([A-Z])/g, ' $1').trim()}
                </label>
                <input
                  type="checkbox"
                  checked={value}
                  onChange={(e) => handlePrivacyToggle(key, e.target.checked)}
                  disabled={saving}
                  className="w-5 h-5 cursor-pointer"
                />
              </div>
            ))}
          </div>
        </div>

        {/* Security Settings */}
        <form
          id="changePasswordForm"
          name="changePasswordForm"
          autoComplete="off"
          onSubmit={(e) => { e.preventDefault(); handleChangePassword(); }}
          className="bg-white rounded-xl shadow-sm p-6 mb-6"
        >
          <h2 className="text-xl font-bold text-gray-800 mb-4">Security</h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">Old Password</label>
              <input 
                type="password"
                name="oldPassword"
                value={oldPassword}
                onChange={(e) => setOldPassword(e.target.value)}
                autoComplete="current-password"
                className="w-full p-3 border border-gray-300 rounded-lg"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">New Password</label>
              <input
                  type="password"
                  name="newPassword"
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  autoComplete="new-password"
                  className="w-full p-3 border border-gray-300 rounded-lg"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">Confirm New Password</label>
              <input
                  type="password"
                  name="confirmPassword"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  autoComplete="new-password"
                  className="w-full p-3 border border-gray-300 rounded-lg"
              />
            </div>
          </div>
          <button
            type="submit"
            disabled={saving}
            className="w-full mt-4 bg-blue-600 text-white py-3 rounded-lg font-bold shadow-lg shadow-blue-100 active:scale-95 transition-all disabled:opacity-50"
          >
            {saving ? 'Saving...' : 'Change Password'}
          </button>
        </form>

        {/* Account Information */}
        <div className="bg-white rounded-xl shadow-sm p-6 mb-6">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-bold text-gray-800">Account Information</h2>
            <button
              onClick={() => setIsEditProfileModalOpen(true)}
              className="text-sm font-medium text-blue-600 hover:text-blue-800"
            >
              Edit Profile
            </button>
          </div>
          <div className="space-y-3">
            <div>
              <p className="text-sm text-gray-600">Name</p>
              <p className="text-lg font-semibold text-gray-800">{user?.name}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Email</p>
              <p className="text-lg font-semibold text-gray-800">{user?.email}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Role</p>
              <p className="text-lg font-semibold text-blue-600 capitalize">{user?.role}</p>
            </div>
          </div>
        </div>

        {/* Logout Button */}
        <div className="bg-white rounded-xl shadow-sm p-6">
          <button
            onClick={handleLogout}
            className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3 px-4 rounded-lg flex items-center justify-center gap-2 transition"
          >
            <LogOut size={20} />
            Logout
          </button>
        </div>
      </div>
    </Layout>
  );
};

export default Settings;

import React, { useState, useEffect, useContext } from 'react';
import { Download, Share2, Award, Clock, Zap, Users, FileText } from 'lucide-react';
import { useParams } from 'react-router-dom';
import api from '../services/api';
import Layout from '../components/layout/Layout';
import Navbar from '../components/layout/Navbar';
import { AuthContext } from '../context/AuthContext';

const VolunteerResume = () => {
  const { user } = useContext(AuthContext);
  const { userId } = useParams();
  const [resume, setResume] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isEditing, setIsEditing] = useState(false);
  const [bio, setBio] = useState('');

  useEffect(() => {
    fetchResume();
  }, [userId]);

  const fetchResume = async () => {
    try {
      setLoading(true);
      const response = await api.get(userId ? `/volunteer-resume/${userId}` : '/volunteer-resume');
      setResume(response.data.data);
      setBio(response.data.data.bio || '');
    } catch (error) {
      console.error('Failed to fetch resume:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateBio = async () => {
    try {
      await api.put('/volunteer-resume', { bio });
      setResume({ ...resume, bio });
      setIsEditing(false);
    } catch (error) {
      console.error('Failed to update bio:', error);
    }
  };

  const handleGenerateCertificate = async () => {
    try {
      const response = await api.post('/volunteer-resume/generate-certificate');
      alert('Certificate generated successfully!');
      window.open(response.data.data.certificateUrl, '_blank');
    } catch (error) {
      console.error('Failed to generate certificate:', error);
    }
  };

  const handleDownloadResume = async () => {
    try {
      const { jsPDF } = await import('jspdf');
      const htmlToImage = await import('html-to-image');

      // Get the resume content element
      const resumeElement = document.getElementById('resume-content');
      if (!resumeElement) {
        alert('Resume content not found');
        return;
      }

      // Convert HTML to image
      const canvas = await htmlToImage.toCanvas(resumeElement, {
        backgroundColor: '#ffffff',
        width: 800,
        height: resumeElement.scrollHeight,
      });

      // Create PDF
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4',
      });

      const imgData = canvas.toDataURL('image/png');
      const imgWidth = 210; // A4 width in mm
      const pageHeight = 295; // A4 height in mm
      const imgHeight = (canvas.height * imgWidth) / canvas.width;
      let heightLeft = imgHeight;

      let position = 0;

      // Add first page
      pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
      heightLeft -= pageHeight;

      // Add additional pages if needed
      while (heightLeft >= 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      // Download the PDF
      pdf.save(`${resume?.userId?.name || 'volunteer'}_resume.pdf`);
    } catch (error) {
      console.error('Failed to download resume:', error);
      alert('Failed to download resume. Please try again.');
    }
  };

  if (loading) {
    return <Layout showBackButton={true}><div className="text-center py-12">Loading resume...</div></Layout>;
  }

  if (!resume) {
    return <Layout showBackButton={true}><div className="text-center py-12">Resume not found</div></Layout>;
  }

  return (
    <Layout showBackButton={true}>
      
      <div id="resume-content" className="max-w-4xl mx-auto p-4 sm:p-6">
        {/* Header */}
        <div className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-lg p-6 sm:p-8 mb-6">
          <div className="flex items-start justify-between mb-4">
            <div>
              <h1 className="text-2xl sm:text-3xl font-bold">{resume.userId?.name}</h1>
              <p className="text-blue-100 text-sm sm:text-base">
                {resume.userId?.branch} • Year {resume.userId?.year}
              </p>
            </div>
            <div className="text-right">
              <div className="text-3xl font-bold">{resume.level}</div>
              <p className="text-blue-100 text-sm">Current Level</p>
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mt-6 pt-6 border-t border-blue-400">
            <div>
              <p className="text-blue-100 text-sm">Total XP</p>
              <p className="text-2xl font-bold">{resume.totalXP}</p>
            </div>
            <div>
              <p className="text-blue-100 text-sm">Hours</p>
              <p className="text-2xl font-bold">{resume.totalHours}</p>
            </div>
            <div>
              <p className="text-blue-100 text-sm">Events</p>
              <p className="text-2xl font-bold">{resume.eventsAttended.length}</p>
            </div>
            <div>
              <p className="text-blue-100 text-sm">Badges</p>
              <p className="text-2xl font-bold">{resume.badges.length}</p>
            </div>
          </div>
        </div>

        {/* Bio Section */}
        <div className="bg-white rounded-lg shadow-md p-6 mb-6">
          <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
            <FileText size={24} className="text-blue-600" />
            About
          </h2>

          {isEditing ? (
            <div className="space-y-4">
              <textarea
                value={bio}
                onChange={(e) => setBio(e.target.value)}
                maxLength={500}
                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                rows={4}
                placeholder="Write a brief bio about yourself and your volunteer journey..."
              />
              <div className="flex gap-3">
                <button
                  onClick={handleUpdateBio}
                  className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition font-medium"
                >
                  Save Bio
                </button>
                <button
                  onClick={() => setIsEditing(false)}
                  className="bg-gray-200 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-300 transition font-medium"
                >
                  Cancel
                </button>
              </div>
            </div>
          ) : (
            <>
              <p className="text-gray-700 mb-4">{bio || 'No bio added yet.'}</p>
              {!userId && (
                <button
                  onClick={() => setIsEditing(true)}
                  className="text-blue-600 hover:text-blue-700 font-medium"
                >
                  Edit Bio
                </button>
              )}
            </>
          )}
        </div>

        {/* Skills Section */}
        {resume.topSkills.length > 0 && (
          <div className="bg-white rounded-lg shadow-md p-6 mb-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
              <Zap size={24} className="text-yellow-500" />
              Top Skills
            </h2>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {resume.topSkills.map((skill, idx) => (
                <div key={idx} className="bg-gradient-to-r from-yellow-50 to-orange-50 p-4 rounded-lg border border-yellow-200">
                  <div className="flex items-start justify-between mb-2">
                    <h3 className="font-bold text-gray-800">{skill.name}</h3>
                    <span className="text-xs bg-yellow-200 text-yellow-800 px-2 py-1 rounded">
                      {skill.proficiency}
                    </span>
                  </div>
                  <p className="text-sm text-gray-600">{skill.tasksCompleted} tasks completed</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Domains Contributed */}
        {resume.domainsContributed.length > 0 && (
          <div className="bg-white rounded-lg shadow-md p-6 mb-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
              <Users size={24} className="text-green-600" />
              Domains Contributed
            </h2>

            <div className="space-y-3">
              {resume.domainsContributed.map((domain, idx) => (
                <div key={idx} className="p-4 bg-green-50 rounded-lg border border-green-200">
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="font-bold text-gray-800">{domain.domainName}</h3>
                    <span className="bg-green-200 text-green-800 text-sm px-2 py-1 rounded">
                      {domain.percentage}%
                    </span>
                  </div>
                  <div className="flex items-center gap-4 text-sm text-gray-600">
                    <span>📋 {domain.tasksCompleted} tasks</span>
                    <span>⏱️ {domain.hoursSpent}h</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-2 mt-2">
                    <div
                      className="bg-green-500 h-2 rounded-full"
                      style={{ width: `${domain.percentage}%` }}
                    />
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Badges */}
        {resume.badges.length > 0 && (
          <div className="bg-white rounded-lg shadow-md p-6 mb-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
              <Award size={24} className="text-purple-600" />
              Achievements ({resume.badges.length})
            </h2>

            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              {resume.badges.map((badge, idx) => (
                <div key={idx} className="text-center p-4 bg-purple-50 rounded-lg border border-purple-200">
                  <div className="text-3xl mb-2">🏅</div>
                  <p className="font-bold text-sm text-gray-800">{badge.name}</p>
                  <p className="text-xs text-gray-600 mt-1">
                    {new Date(badge.earnedAt).toLocaleDateString()}
                  </p>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Actions */}
        <div className="bg-white rounded-lg shadow-md p-6 flex flex-col sm:flex-row gap-3">
          <button
            onClick={handleGenerateCertificate}
            className="flex items-center justify-center gap-2 bg-green-600 text-white px-6 py-3 rounded-lg hover:bg-green-700 transition font-medium"
          >
            <Award size={20} />
            Generate Certificate
          </button>
          <button
            onClick={handleDownloadResume}
            className="flex items-center justify-center gap-2 bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition font-medium"
          >
            <Download size={20} />
            Download Resume
          </button>
          <button
            onClick={() => {
              navigator.share({
                title: `${resume.userId?.name}'s Volunteer Resume`,
                url: window.location.href,
              });
            }}
            className="flex items-center justify-center gap-2 bg-purple-600 text-white px-6 py-3 rounded-lg hover:bg-purple-700 transition font-medium"
          >
            <Share2 size={20} />
            Share
          </button>
        </div>
      </div>
    </Layout>
  );
};

export default VolunteerResume;

